1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	};
10	
11	const RUNE_BLOCK_SIZE = 3;
12	const RUNE_BLOCK_PRICE = 60;
13	
14	type Item = { type: string };
15	type Step = { op: string; items: Item[] };
16	type Scenario = { steps: Step[] };
17	
18	const basePremiumForItem = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
19	
20	const basePremiumFor = (items: Item[]): number => {
21	  const runeCount = items.filter((item) => item.type === "rune").length;
22	  if (runeCount === RUNE_BLOCK_SIZE) return RUNE_BLOCK_PRICE;
23	  return items.reduce((sum, item) => sum + basePremiumForItem(item), 0);
24	};
25	
26	export const runScenario = (input: unknown): { results: Array<{ premium: number }> } => {
27	  const { steps } = input as Scenario;
28	  const premium = basePremiumFor(steps[0].items) + PROCESSING_FEE;
29	  return { results: [{ premium }] };
30	};
